+      // Sustained-load throughput: process N independent forwards
+      // back-to-back, report sequences/sec and tokens/sec. Single-
+      // forward latency is what one user feels; throughput is what
+      // a batch processor or AI proxy sees.
+      const THROUGHPUT_ITERS = 30;
+      async function measureThroughput(label, filter, text, approxTokens) {
+        for (let i = 0; i < WARMUP; i++) await filter.detect(text);
+        const t0 = performance.now();
+        for (let i = 0; i < THROUGHPUT_ITERS; i++) await filter.detect(text);
+        const elapsed = performance.now() - t0;
+        const seqPerSec = (THROUGHPUT_ITERS / elapsed) * 1000;
+        const tokPerSec = seqPerSec * approxTokens;
+        log(`  ${label.padEnd(18)} ${seqPerSec.toFixed(1)} seq/s, ${tokPerSec.toFixed(0)} tok/s (${THROUGHPUT_ITERS} iters in ${elapsed.toFixed(0)}ms)`);
+        return { seqPerSec, tokPerSec };
+      }
+
